  "questionProse": [
    "कौन सा डेटा स्ट्रक्चर प्रायोरिटी क्यू को लागू करने के लिए आमतौर पर उपयोग किया जाता है?"
  ],
  "explanationProse": [
    "प्रायोरिटी क्यू अक्सर हीप का उपयोग करके लागू किया जाता है क्योंकि यह उच्चतम या न्यूनतम प्रायोरिटी वाले तत्व को कुशलता से निकालता है।"
  ]
}
